            $xml = simplexml_load_string($data);

            if ($xml === false) {
                throw new \UnexpectedValueException("Unable to parse XML content");
            }

            $result = [];
            foreach ($xml-&gt;children() as $child) {
                $fields = [];
                foreach ($child as $key =&gt; $value) {
                    $fields[$key] = (string) $value;
                }
                $result[] = $fields;
            }

            return $result;
        }
    }
